    "    'Normal'               : 'Normal',\n",
    "    'DDoS_UDP'             : 'DDoS',\n",
    "    'DDoS_ICMP'            : 'DDoS',\n",
    "    'DDoS_HTTP'            : 'DDoS',\n",
    "    'DDoS_TCP'             : 'DDoS',\n",
    "    'Backdoor'             : 'Backdoor',\n",
    "    'Uploading'            : 'Backdoor',\n",
    "    'Ransomware'           : 'Backdoor',\n",
    "    'MITM'                 : 'MITM',\n",
    "    'SQL_injection'        : 'Intrusion',\n",
    "    'XSS'                  : 'Intrusion',\n",
    "    'Password'             : 'Intrusion',\n",
    "    'Fingerprinting'       : 'Reconnaissance',\n",
    "    'Vulnerability_scanner': 'Reconnaissance',\n",
    "    'Port_Scanning'        : 'Reconnaissance'\n",
    "}"
