    "\n",
    "#plt.savefig('timeseries_prevention_timeline.png',\n",
    "            dpi=300, bbox_inches='tight', facecolor='#0f172a')\n",
    "plt.show()\n",
    "\n",
    "print('Time series figure saved.')"
